  "inlineSchema": "// Conference Child Management System - Prisma Schema\n// Learn more: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  output        = \"../generated/prisma\"\n  binaryTargets = [\"native\", \"linux-musl-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================================\n// Admin & Authentication Models\n// ============================================================================\n\nmodel AdminUser {\n  id           String    @id @default(cuid())\n  username     String    @unique\n  passwordHash String\n  name         String\n  createdAt    DateTime  @default(now())\n  lastLogin    DateTime?\n  isActive     Boolean   @default(true)\n\n  // Relations\n  checkInsPerformed  CheckInRecord[] @relation(\"CheckInStaff\")\n  checkOutsPerformed CheckInRecord[] @relation(\"CheckOutStaff\")\n\n  @@map(\"admin_users\")\n}\n\n// ============================================================================\n// Family & Contact Models\n// ============================================================================\n\nmodel Family {\n  id                    String    @id @default(cuid())\n  lastParticipationDate DateTime?\n\n  // Relations\n  parents  Parent[]\n  children Child[]\n\n  @@map(\"families\")\n}\n\nmodel Parent {\n  id                    String    @id @default(cuid())\n  name                  String\n  phone                 String?\n  email                 String?\n  relationshipType      String // \"Mom\", \"Dad\", or free text\n  lastParticipationDate DateTime?\n  familyId              String\n\n  // Relations\n  family Family @relation(fields: [familyId], references: [id], onDelete: Cascade)\n\n  @@index([familyId])\n  @@map(\"parents\")\n}\n\n// ============================================================================\n// Child Model\n// ============================================================================\n\nmodel Child {\n  id                    String    @id @default(cuid())\n  firstName             String\n  lastName              String\n  birthdate             DateTime\n  allergies             String?\n  notes                 String?\n  qrToken               String?   @unique // UUID, generated on first check-in\n  lastParticipationDate DateTime?\n  familyId              String\n\n  // Relations\n  family         Family          @relation(fields: [familyId], references: [id], onDelete: Cascade)\n  checkInRecords CheckInRecord[]\n  tickets        Ticket[]\n\n  @@index([qrToken])\n  @@index([lastName])\n  @@index([familyId])\n  @@map(\"children\")\n}\n\n// ============================================================================\n// Event & Session Models\n// ============================================================================\n\nmodel Event {\n  id        String   @id @default(cuid())\n  name      String\n  startDate DateTime\n  endDate   DateTime\n\n  // Relations\n  sessions Session[]\n\n  @@map(\"events\")\n}\n\nmodel Session {\n  id             String   @id @default(cuid())\n  name           String\n  startTime      DateTime\n  endTime        DateTime\n  isActive       Boolean  @default(false)\n  requiresTicket Boolean  @default(false)\n  eventId        String\n\n  // Relations\n  event          Event           @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  checkInRecords CheckInRecord[]\n  tickets        Ticket[]\n\n  @@index([eventId])\n  @@index([isActive])\n  @@map(\"sessions\")\n}\n\n// ============================================================================\n// Ticket & Check-In Models\n// ============================================================================\n\nmodel Ticket {\n  id        String  @id @default(cuid())\n  type      String // \"EVENT_PASS\", \"SESSION_TICKET\", \"NONE\"\n  childId   String\n  sessionId String? // null for event pass\n\n  // Relations\n  child   Child    @relation(fields: [childId], references: [id], onDelete: Cascade)\n  session Session? @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  @@index([childId])\n  @@index([sessionId])\n  @@map(\"tickets\")\n}\n\nmodel CheckInRecord {\n  id              String    @id @default(cuid())\n  checkInTime     DateTime  @default(now())\n  checkOutTime    DateTime?\n  pickedUpBy      String?\n  childId         String\n  sessionId       String\n  checkInStaffId  String\n  checkOutStaffId String?\n\n  // Relations\n  child         Child      @relation(fields: [childId], references: [id], onDelete: Cascade)\n  session       Session    @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  checkInStaff  AdminUser  @relation(\"CheckInStaff\", fields: [checkInStaffId], references: [id])\n  checkOutStaff AdminUser? @relation(\"CheckOutStaff\", fields: [checkOutStaffId], references: [id])\n\n  @@unique([childId, sessionId, checkInTime])\n  @@index([childId])\n  @@index([sessionId])\n  @@index([checkInStaffId])\n  @@index([checkOutStaffId])\n  @@map(\"check_in_records\")\n}\n\n// ============================================================================\n// Audit Log Model\n// ============================================================================\n\nmodel AuditLog {\n  id         String   @id @default(cuid())\n  timestamp  DateTime @default(now())\n  userId     String // AdminUser ID\n  action     String // \"CHECK_IN\", \"CHECK_OUT\", \"CREATE_FAMILY\", etc.\n  entityType String // \"Child\", \"Family\", \"Session\", etc.\n  entityId   String\n  details    Json? // Additional context\n\n  @@index([timestamp])\n  @@index([userId])\n  @@index([entityType])\n  @@map(\"audit_logs\")\n}\n",
